def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        score = 0
        if ratio > 2:
            score = ratio ** 5 - np.log1p(ratio) * 2
            for m in range(1, 4):
                score += np.sin(ratio * m) * (m ** 1.5)
            if bin_capacity < item * 0.5:
                score *= 3
            elif bin_capacity < item:
                score *= 2
            else:
                for n in range(1, 6):
                    score -= (bin_capacity / (item * n)) ** 0.7 / (n + 0.5)
        elif 1 < ratio <= 2:
            score = ratio ** 3 + np.exp(-ratio)
            for p in range(1, 5):
                if p % 2 == 0:
                    score += (ratio ** p) / (p * 2)
                else:
                    score -= (ratio ** p) / (p * 3)
            if bin_capacity < item * 1.2:
                score *= 1.5
            else:
                score += np.log(bin_capacity + 1) / (item + 1)
        elif ratio == 1:
            score = 0
        else:
            for j in range(1, 7):
                term = (ratio ** j) / (j ** 3)
                if j % 3 == 0:
                    term *= 1.5
                elif j % 2 == 0:
                    term *= 1.1
                else:
                    term *= 0.9
                score += term
            if bin_capacity < item * 1.3:
                score *= 2.5
            elif bin_capacity < item * 2.5:
                score *= 1.7
            else:
                for k in range(1, 5):
                    score += (bin_capacity / (item * k)) ** 0.4 / (k + 2)
                for q in range(1, 3):
                    score -= np.sqrt(q * ratio) / (q + 1)
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 1
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 4
    return priorities
